principle.example:
-- GOOD: Using REFERENCE
DECLARE inputRef REFERENCE TO InputRoot.XMLNSC.Data;
MOVE inputRef FIRSTCHILD;
WHILE LASTMOVE(inputRef) DO
  -- Process element
  MOVE inputRef NEXTSIBLING;
END WHILE;

-- BAD: Direct navigation causes implicit copying
SET OutputRoot.XMLNSC.Data.Element = InputRoot.XMLNSC.Data.Element;

-- GOOD: Selective copying
CREATE PROCEDURE CopyMessageHeaders() BEGIN
  DECLARE I INTEGER 1;
  DECLARE J INTEGER;
  SET J = CARDINALITY(InputRoot.*[]);
  WHILE I < J DO
    SET OutputRoot.*[I] = InputRoot.*[I];
    SET I = I + 1;
  END WHILE;
END;

-- BAD: Unnecessary full copy
CREATE PROCEDURE CopyEntireMessage() BEGIN
  SET OutputRoot = InputRoot;
END;

BROKER SCHEMA com.organization.esb

-- External variables for configuration
DECLARE supportGroupDL EXTERNAL CHARACTER '';
DECLARE SendMail EXTERNAL CHARACTER 'YES';

-- Shared variables for cross-module state
DECLARE Error_Code SHARED CHARACTER '';
DECLARE Error_Text SHARED CHARACTER '';

CREATE COMPUTE MODULE ProcessMessage_Compute
  CREATE FUNCTION Main() RETURNS BOOLEAN
  BEGIN
    -- Local variables
    DECLARE messageId CHARACTER;
    DECLARE timestamp TIMESTAMP;
    DECLARE counter INTEGER 0;

    -- Implementation
    RETURN TRUE;
  END;
END MODULE;

-- GOOD: Calculate cardinality once
DECLARE counter INTEGER;
DECLARE index INTEGER 1;
SET counter = CARDINALITY(InputRoot.XMLNSC.Data.Items.Item[]);

WHILE index <= counter DO
  -- Process item
  SET index = index + 1;
END WHILE;

-- BAD: Recalculating cardinality in loop condition
DECLARE index INTEGER 1;
WHILE index <= CARDINALITY(InputRoot.XMLNSC.Data.Items.Item[]) DO
  -- Process item (cardinality calculated every iteration!)
  SET index = index + 1;
END WHILE;

-- GOOD: Using LASTMOVE
DECLARE fieldRef REFERENCE TO InputRoot.XMLNSC.Data.OptionalField;
IF LASTMOVE(fieldRef) THEN
  -- Field exists, process it
  SET OutputRoot.XMLNSC.Result = fieldRef;
END IF;

-- GOOD: Using CARDINALITY
IF CARDINALITY(InputRoot.XMLNSC.Data.Items[]) > 0 THEN
  -- Items exist
END IF;

-- GOOD: Using FIELDTYPE
IF FIELDTYPE(InputRoot.MQMD.PutApplName) IS NOT NULL THEN
  -- Field exists and has a type
END IF;

module_structure.standard_template:
BROKER SCHEMA com.organization.esb

-- External variables (configurable via properties)
DECLARE configParam EXTERNAL CHARACTER '';

-- Shared variables (cross-module state)
DECLARE sharedState SHARED CHARACTER '';

/*******************************************************************************
* Node: NodeName_Compute
* Module Name: NodeName_Compute
*
* Description: Brief description of what this module does
*
* Ver    Author              Date        Description
* ===    =======             ====        ===========
* 1      Developer Name      MM/DD/YYYY  Initial version
*
********************************************************************************/

CREATE COMPUTE MODULE NodeName_Compute
  CREATE FUNCTION Main() RETURNS BOOLEAN
  BEGIN
    -- Main processing logic
    CALL CopyMessageHeaders();

    -- Business logic here

    RETURN TRUE;
  END;

  CREATE PROCEDURE CopyMessageHeaders() BEGIN
    DECLARE I INTEGER 1;
    DECLARE J INTEGER;
    SET J = CARDINALITY(InputRoot.*[]);
    WHILE I < J DO
      SET OutputRoot.*[I] = InputRoot.*[I];
      SET I = I + 1;
    END WHILE;
  END;
END MODULE;

